import time
import functools
from enum import Enum

class CircuitBreakerState(Enum):
    CLOSED = "CLOSED"
    OPEN = "OPEN"
    HALF_OPEN = "HALF_OPEN"

class CircuitBreakerOpenException(Exception):
    """Exception raised when the circuit breaker is open."""
    pass

class CircuitBreaker:
    def __init__(self, failure_threshold: int = 5, recovery_timeout: int = 60, expected_successes: int = 1):
        if failure_threshold <= 0:
            raise ValueError("failure_threshold must be greater than 0")
        if recovery_timeout <= 0:
            raise ValueError("recovery_timeout must be greater than 0")
        if expected_successes <= 0:
            raise ValueError("expected_successes must be greater than 0")

        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.expected_successes = expected_successes

        self.state = CircuitBreakerState.CLOSED
        self.failure_count = 0
        self.success_count = 0
        self.last_failure_time = 0.0

    def _reset_counts(self):
        self.failure_count = 0
        self.success_count = 0

    def _open(self):
        self.state = CircuitBreakerState.OPEN
        self.last_failure_time = time.time()

    def _half_open(self):
        self.state = CircuitBreakerState.HALF_OPEN
        self.success_count = 0

    def _close(self):
        self.state = CircuitBreakerState.CLOSED
        self._reset_counts()

    def _on_success(self):
        if self.state == CircuitBreakerState.CLOSED:
            self._reset_counts()
        elif self.state == CircuitBreakerState.HALF_OPEN:
            self.success_count += 1
            if self.success_count >= self.expected_successes:
                self._close()

    def _on_failure(self):
        if self.state == CircuitBreakerState.CLOSED:
            self.failure_count += 1
            if self.failure_count >= self.failure_threshold:
                self._open()
        elif self.state == CircuitBreakerState.HALF_OPEN:
            self._open()

    def __call__(self, func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if self.state == CircuitBreakerState.OPEN:
                if time.time() > self.last_failure_time + self.recovery_timeout:
                    self._half_open()
                else:
                    raise CircuitBreakerOpenException("Circuit breaker is OPEN.")

            try:
                result = func(*args, **kwargs)
                self._on_success()
                return result
            except Exception:
                self._on_failure()
                raise

        return wrapper
